/* ADC driver with callback-based interface */
#ifndef ADC_DRV_H
#define ADC_DRV_H

#include <stdint.h>

/* Callback signature changed: added user context pointer and timestamp */
typedef void (*adc_callback_t)(uint8_t channel, uint16_t raw_value,
                               uint32_t timestamp_us, void *user_ctx);

typedef struct {
    uint8_t        channel_mask;
    uint32_t       sample_rate_hz;
    adc_callback_t on_sample;
    void          *user_ctx;  /* NEW: passed back in callback */
} adc_config_t;

int  adc_open(const adc_config_t *cfg);
void adc_start(void);
void adc_stop(void);
void adc_close(void);

#endif

